/// Fast lookup by ISO code.
final Map<String, Country> _countryByIso = {
  for (final c in allCountries) c.isoCode: c,
};

/// Returns the country for the given ISO 3166-1 alpha-2 code, or null.
Country? countryByIso(String isoCode) => _countryByIso[isoCode.toUpperCase()];

/// Returns all countries for a given continent.
List<Country> countriesFor(Continent continent) =>
    allCountries.where((c) => c.continent == continent).toList();
